import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import './Login.css';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-wrapper">
        {/* Header Section */}
        <div className="login-header">
          <h1 className="login-title">
            Welcome to <span className="highlight">TeamTask</span>
          </h1>
          <p className="login-subtitle">Manage your team projects and tasks efficiently</p>
        </div>

        {/* Login Card */}
        <div className="login-card">
          <form onSubmit={handleSubmit} className="login-form">
            {/* Email Input */}
            <div className="form-group">
              <label className="form-label">📧 Email Address</label>
              <input
                type="email"
                name="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={handleChange}
                className="form-input"
                required
              />
            </div>

            {/* Password Input */}
            <div className="form-group">
              <label className="form-label">🔐 Password</label>
              <input
                type="password"
                name="password"
                placeholder="Enter your password"
                value={form.password}
                onChange={handleChange}
                className="form-input"
                required
              />
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              className="btn-signin"
              disabled={loading}
            >
              {loading ? '⏳ Signing in...' : '✓ Sign In'}
            </button>
          </form>

          {/* Sign Up Link */}
          <div className="login-footer">
            <span className="footer-text">New here?</span>
            <Link to="/register" className="link-register">Create Account</Link>
          </div>
        </div>

        {/* Info Section */}
        <div className="info-section">
          <div className="info-box">
            <p className="info-title">👤 Admin Role</p>
            <p className="info-text">Create and manage projects & tasks</p>
          </div>
          <div className="info-box">
            <p className="info-title">📋 Member Role</p>
            <p className="info-text">View tasks and submit updates</p>
          </div>
        </div>
      </div>
    </div>
  );
}
